import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(false);

  // Auto open sidebar on large screens
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) {
        setIsOpen(true);
      } else {
        setIsOpen(false);
      }
    };

    handleResize();
    window.addEventListener("resize", handleResize);

    return () => window.removeEventListener("resize", handleResize);
  }, []);

  return (
    <div className={design.layout.wrapper}>

      {/* 🔥 Overlay (Mobile & Tablet) */}
      <AnimatePresence>
        {isOpen && window.innerWidth < 1024 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className={`fixed inset-0 ${design.colors.overlay} z-40`}
            onClick={() => setIsOpen(false)}
          />
        )}
      </AnimatePresence>

      {/* 🔥 Sidebar */}
      <motion.aside
        initial={false}
        animate={{ x: isOpen ? 0 : -260 }}
        transition={{ duration: 0.3 }}
        className={`${design.colors.sidebar} ${design.layout.sidebar}`}
      >
        <h2 className="text-2xl font-bold text-indigo-400">
          Admin Panel
        </h2>

        <nav className="space-y-3">
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Dashboard
          </div>
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Products
          </div>
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Orders
          </div>
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Users
          </div>
        </nav>
      </motion.aside>

      {/* 🔥 Right Content */}
      <div className={`${design.layout.contentWrapper} ${design.layout.desktopSpacing}`}>

        {/* Navbar */}
        <div className={design.layout.navbar}>
          
          {/* Toggle button (Hidden on large screens) */}
          <button
            onClick={() => setIsOpen(!isOpen)}
            className={`lg:hidden ${design.colors.toggleBtn}`}
          >
            ☰
          </button>

          <h1 className="font-semibold text-base sm:text-lg">
            Dashboard
          </h1>

          <div className="flex items-center gap-3">
            <span className="text-xs sm:text-sm text-gray-600">
              {adminInfo?.name}
            </span>
            <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
          </div>
        </div>

        {/* Main Content */}
        <div className={design.layout.content}>
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4 }}
          >
            <h2 className="text-xl sm:text-2xl lg:text-3xl font-bold mb-4">
              Welcome Back 👋
            </h2>

            <p className="text-gray-600 text-sm sm:text-base">
              Fully responsive admin dashboard using Tailwind CSS and Framer Motion.
            </p>
          </motion.div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
